/**
 * @summary Add comment to reconciliation
 */
export const addReconciliationComment = async (id: number,
    reconciliationCommentInput: ReconciliationCommentInput, options?: RequestInit): Promise<ReconciliationComment> => {

  return customFetch<ReconciliationComment>(getAddReconciliationCommentUrl(id),
  {
    ...options,
    method: 'POST',
    headers: { 'Content-Type': 'application/json', ...options?.headers },
    body: JSON.stringify(
      reconciliationCommentInput,)
  }
);}




